import{_ as t,c as e,o as n,a as r}from"./app.b430f5d9.js";const m=JSON.parse('{"title":"Harness Engineer","description":"","frontmatter":{"title":"Harness Engineer"},"headers":[{"level":2,"title":"\u{1F6E1}\uFE0F \u6A21\u5757\u4E00\uFF1A\u7EA6\u675F\u673A\u5236 (Guardrails & Constraints)","slug":"\u{1F6E1}\uFE0F-\u6A21\u5757\u4E00-\u7EA6\u675F\u673A\u5236-guardrails-constraints","link":"#\u{1F6E1}\uFE0F-\u6A21\u5757\u4E00-\u7EA6\u675F\u673A\u5236-guardrails-constraints","children":[]},{"level":2,"title":"\u{1F9E0} \u6A21\u5757\u4E8C\uFF1A\u4E0A\u4E0B\u6587\u5DE5\u7A0B (Context Engineering)","slug":"\u{1F9E0}-\u6A21\u5757\u4E8C-\u4E0A\u4E0B\u6587\u5DE5\u7A0B-context-engineering","link":"#\u{1F9E0}-\u6A21\u5757\u4E8C-\u4E0A\u4E0B\u6587\u5DE5\u7A0B-context-engineering","children":[]},{"level":2,"title":"\u{1F6E0}\uFE0F \u6A21\u5757\u4E09\uFF1A\u5DE5\u5177\u4E0E\u6280\u80FD\u96C6\u6210 (Tools & Skills)","slug":"\u{1F6E0}\uFE0F-\u6A21\u5757\u4E09-\u5DE5\u5177\u4E0E\u6280\u80FD\u96C6\u6210-tools-skills","link":"#\u{1F6E0}\uFE0F-\u6A21\u5757\u4E09-\u5DE5\u5177\u4E0E\u6280\u80FD\u96C6\u6210-tools-skills","children":[]},{"level":2,"title":"\u{1F504} \u6A21\u5757\u56DB\uFF1A\u53CD\u9988\u56DE\u8DEF (Feedback Loop)","slug":"\u{1F504}-\u6A21\u5757\u56DB-\u53CD\u9988\u56DE\u8DEF-feedback-loop","link":"#\u{1F504}-\u6A21\u5757\u56DB-\u53CD\u9988\u56DE\u8DEF-feedback-loop","children":[]},{"level":2,"title":"\u{1F9E9} \u6A21\u5757\u4E94\uFF1A\u7F16\u6392\u4E0E\u534F\u8C03 (Orchestration & Coordination)","slug":"\u{1F9E9}-\u6A21\u5757\u4E94-\u7F16\u6392\u4E0E\u534F\u8C03-orchestration-coordination","link":"#\u{1F9E9}-\u6A21\u5757\u4E94-\u7F16\u6392\u4E0E\u534F\u8C03-orchestration-coordination","children":[]},{"level":2,"title":"\u{1F4C8} \u6A21\u5757\u516D\uFF1A\u71B5\u7BA1\u7406\u4E0E\u6301\u7EED\u6539\u8FDB (Entropy Management)","slug":"\u{1F4C8}-\u6A21\u5757\u516D-\u71B5\u7BA1\u7406\u4E0E\u6301\u7EED\u6539\u8FDB-entropy-management","link":"#\u{1F4C8}-\u6A21\u5757\u516D-\u71B5\u7BA1\u7406\u4E0E\u6301\u7EED\u6539\u8FDB-entropy-management","children":[]},{"level":2,"title":"\u76F8\u5173\u6587\u7AE0","slug":"\u76F8\u5173\u6587\u7AE0","link":"#\u76F8\u5173\u6587\u7AE0","children":[]}],"relativePath":"harness/harness-engineer.md"}'),i={name:"harness/harness-engineer.md"},o=r('<h1 id="harness-engineer" tabindex="-1">Harness Engineer <a class="header-anchor" href="#harness-engineer" aria-hidden="true">#</a></h1><p>\u8FD9\u662F AI Agent \u8FD0\u884C\u7684&quot;\u64CD\u4F5C\u7CFB\u7EDF&quot;\uFF0C\u786E\u4FDD\u6A21\u578B\u5728\u5B89\u5168\u3001\u53EF\u9760\u3001\u9AD8\u6548\u7684\u8FB9\u754C\u5185\u81EA\u4E3B\u5B8C\u6210\u4EFB\u52A1\u3002</p><p>Agent = Model (\u667A\u80FD) + Harness (\u64CD\u4F5C\u7CFB\u7EDF)</p><p>\u4E00\u4E2A\u4F18\u79C0\u7684 Harness \u5DE5\u7A0B\u6838\u5FC3\u662F\u6574\u5408\u4EE5\u4E0B\u516D\u4E2A\u5173\u952E\u6A21\u5757\uFF1A</p><hr><h2 id="\u{1F6E1}\uFE0F-\u6A21\u5757\u4E00-\u7EA6\u675F\u673A\u5236-guardrails-constraints" tabindex="-1">\u{1F6E1}\uFE0F \u6A21\u5757\u4E00\uFF1A\u7EA6\u675F\u673A\u5236 (Guardrails &amp; Constraints) <a class="header-anchor" href="#\u{1F6E1}\uFE0F-\u6A21\u5757\u4E00-\u7EA6\u675F\u673A\u5236-guardrails-constraints" aria-hidden="true">#</a></h2><p><strong>\u5B89\u5168\u57FA\u77F3</strong>\uFF0C\u4E3A AI \u7684\u884C\u4E3A\u5212\u5B9A\u4E0D\u53EF\u903E\u8D8A\u7684&quot;\u786C\u8FB9\u754C&quot;\u3002</p><ul><li><strong>\u5B9A\u4E49\u4E0E\u76EE\u7684</strong>\uFF1A\u901A\u8FC7\u5F3A\u5236\u6027\u89C4\u5219\uFF08\u67B6\u6784\u8FB9\u754C\u3001\u4F9D\u8D56\u767D\u540D\u5355\u3001\u7981\u6B62\u884C\u4E3A\u3001\u6C99\u7BB1\u73AF\u5883\uFF09\u9650\u5236 Agent\uFF0C\u4F7F\u5176\u5728\u5B89\u5168\u8303\u56F4\u5185\u81EA\u4E3B\u884C\u52A8\u3002</li><li><strong>\u5B9E\u73B0\u65B9\u5F0F</strong>\uFF1A <ul><li>AI \u53CB\u597D\u7684 Linter\uFF1A\u5C06&quot;\u4EE3\u7801\u54C1\u5473&quot;\u8F6C\u5316\u4E3A\u673A\u5668\u53EF\u8BFB\u7684\u89C4\u5219\uFF0CAI \u9519\u8BEF\u65F6\u4E0D\u4EC5\u62A5\u544A\u8FD8\u76F4\u63A5\u7ED9\u51FA\u4FEE\u590D\u5EFA\u8BAE\u3002</li><li>\u53CC\u91CD\u5BA1\u8BA1\u673A\u5236\uFF1A\u72EC\u7ACB&quot;\u5BA1\u8BA1 Agent&quot;\u5B9E\u65F6\u5BA1\u67E5\u63D0\u4EA4\uFF0C\u5B9E\u73B0\u4EBA\u673A\u53CC\u91CD\u628A\u5173\u3002</li><li>\u6743\u9650\u4E0E\u6C99\u7BB1\uFF1A\u901A\u8FC7\u6743\u9650\u7BA1\u7406\u548C\u6C99\u7BB1\u73AF\u5883\u9694\u79BB\u64CD\u4F5C\uFF0C\u9632\u6B62\u8BEF\u64CD\u4F5C\u5F71\u54CD\u6838\u5FC3\u7CFB\u7EDF\u3002</li></ul></li></ul><hr><h2 id="\u{1F9E0}-\u6A21\u5757\u4E8C-\u4E0A\u4E0B\u6587\u5DE5\u7A0B-context-engineering" tabindex="-1">\u{1F9E0} \u6A21\u5757\u4E8C\uFF1A\u4E0A\u4E0B\u6587\u5DE5\u7A0B (Context Engineering) <a class="header-anchor" href="#\u{1F9E0}-\u6A21\u5757\u4E8C-\u4E0A\u4E0B\u6587\u5DE5\u7A0B-context-engineering" aria-hidden="true">#</a></h2><p><strong>\u4FE1\u606F\u4E2D\u67A2</strong>\uFF0C\u786E\u4FDD AI \u5728\u6B63\u786E\u7684\u65F6\u95F4\u83B7\u5F97\u6B63\u786E\u7C92\u5EA6\u7684\u4FE1\u606F\u3002</p><ul><li><strong>\u5B9A\u4E49\u4E0E\u76EE\u7684</strong>\uFF1A\u52A8\u6001\u63D0\u4F9B\u6267\u884C\u4EFB\u52A1\u6240\u9700\u7684&quot;\u80CC\u666F\u77E5\u8BC6&quot;\uFF08\u9879\u76EE\u6587\u6863\u3001\u67B6\u6784\u56FE\u3001\u5386\u53F2\u51B3\u7B56\u3001\u7CFB\u7EDF\u72B6\u6001\uFF09\uFF0C\u907F\u514D\u4FE1\u606F\u4E0D\u8DB3\u6216\u8FC7\u8F7D\u5BFC\u81F4\u7684\u5E7B\u89C9\u3002</li><li><strong>\u5B9E\u73B0\u65B9\u5F0F</strong>\uFF1A <ul><li>\u6E10\u8FDB\u5F0F\u62AB\u9732\uFF1A\u901A\u8FC7\u5206\u5C42\uFF08\u5982 <a href="http://CLAUDE.md" target="_blank" rel="noreferrer">CLAUDE.md</a> \u4E09\u7EA7\u6587\u4EF6\u7CFB\u7EDF\uFF09\u6309\u9700\u52A0\u8F7D\u4FE1\u606F\uFF0C\u89E3\u51B3\u957F\u4E0A\u4E0B\u6587\u7A97\u53E3\u5E26\u6765\u7684\u6CE8\u610F\u529B\u8870\u51CF\u548C\u6210\u672C\u95EE\u9898\u3002</li><li>\u5DE5\u7A0B\u77E5\u8BC6\u5E95\u5EA7\uFF1A\u6784\u5EFA\u5305\u542B\u4EE3\u7801\u56FE\u8C31\u3001Commit \u56FE\u8C31\u3001RepoWiki \u548C\u6301\u4E45\u5316\u8BB0\u5FC6\u7684\u7ACB\u4F53\u77E5\u8BC6\u7F51\u7EDC\u3002</li><li>\u8FD0\u884C\u65F6\u6570\u636E\u63A5\u5165\uFF1A\u901A\u8FC7 LogQL/PromQL \u7B49\u5DE5\u5177\u52A8\u6001\u67E5\u8BE2\u65E5\u5FD7\u3001\u6307\u6807\u548C\u73AF\u5883\u6620\u5C04\u3002</li></ul></li></ul><hr><h2 id="\u{1F6E0}\uFE0F-\u6A21\u5757\u4E09-\u5DE5\u5177\u4E0E\u6280\u80FD\u96C6\u6210-tools-skills" tabindex="-1">\u{1F6E0}\uFE0F \u6A21\u5757\u4E09\uFF1A\u5DE5\u5177\u4E0E\u6280\u80FD\u96C6\u6210 (Tools &amp; Skills) <a class="header-anchor" href="#\u{1F6E0}\uFE0F-\u6A21\u5757\u4E09-\u5DE5\u5177\u4E0E\u6280\u80FD\u96C6\u6210-tools-skills" aria-hidden="true">#</a></h2><p><strong>&quot;\u624B\u811A&quot;</strong>\uFF0C\u8BA9 AI \u80FD\u611F\u77E5\u4E16\u754C\u5E76\u91C7\u53D6\u884C\u52A8\u3002</p><ul><li><strong>\u5B9A\u4E49\u4E0E\u76EE\u7684</strong>\uFF1A\u8D4B\u4E88 AI \u6267\u884C\u5177\u4F53\u64CD\u4F5C\u7684\u80FD\u529B\uFF08\u6587\u4EF6\u7CFB\u7EDF\u3001\u4EE3\u7801\u8FD0\u884C\u3001API \u8C03\u7528\u3001\u6D4F\u89C8\u5668\u64CD\u4F5C\u7B49\uFF09\uFF0C\u4F7F\u5176\u4E0D\u4EC5\u80FD&quot;\u60F3&quot;\uFF0C\u8FD8\u80FD&quot;\u505A&quot;\u3002</li><li><strong>\u5B9E\u73B0\u65B9\u5F0F</strong>\uFF1A <ul><li>\u7CBE\u7B80\u6838\u5FC3\u5DE5\u5177\u5E93\uFF1A\u7CBE\u6311\u7EC6\u9009\u5C11\u91CF\u529F\u80FD\u5F3A\u5927\u7684&quot;\u80FD\u529B\u539F\u8BED&quot;\uFF08\u5982\u8BFB\u3001\u5199\u3001\u6267\u884C\u3001\u67E5\u8BE2\uFF09\uFF0C\u8BA9 AI \u81EA\u4E3B\u7EC4\u5408\u5B8C\u6210\u4EFB\u52A1\u3002</li><li>\u6587\u4EF6\u7CFB\u7EDF\u62BD\u8C61\uFF1A\u63D0\u4F9B\u6807\u51C6\u5316&quot;\u5DE5\u4F5C\u533A&quot;\uFF0C\u5B9E\u73B0\u8DE8\u4F1A\u8BDD\u72B6\u6001\u6301\u4E45\u5316\u548C\u957F\u5468\u671F\u4EFB\u52A1\u5904\u7406\u3002</li></ul></li></ul><hr><h2 id="\u{1F504}-\u6A21\u5757\u56DB-\u53CD\u9988\u56DE\u8DEF-feedback-loop" tabindex="-1">\u{1F504} \u6A21\u5757\u56DB\uFF1A\u53CD\u9988\u56DE\u8DEF (Feedback Loop) <a class="header-anchor" href="#\u{1F504}-\u6A21\u5757\u56DB-\u53CD\u9988\u56DE\u8DEF-feedback-loop" aria-hidden="true">#</a></h2><p><strong>&quot;\u795E\u7ECF&quot;</strong>\uFF0C\u8BA9 AI \u80FD\u591F\u89C2\u5BDF\u81EA\u8EAB\u884C\u4E3A\u5E76\u6301\u7EED\u6539\u8FDB\u3002</p><ul><li><strong>\u5B9A\u4E49\u4E0E\u76EE\u7684</strong>\uFF1A\u6784\u5EFA\u81EA\u52A8\u5316\u9A8C\u8BC1\u3001\u6D4B\u8BD5\u548C\u7EA0\u9519\u673A\u5236\uFF0C\u5BF9\u5DE5\u4F5C\u6210\u679C\u8FDB\u884C\u6821\u9A8C\uFF0C\u5E76\u80FD\u4ECE\u9519\u8BEF\u4E2D\u5B66\u4E60\u3002</li><li><strong>\u5B9E\u73B0\u65B9\u5F0F</strong>\uFF1A <ul><li>\u81EA\u6211\u9A8C\u8BC1\u673A\u5236\uFF1A\u5F3A\u5236\u52A0\u5165&quot;\u8BA1\u5212-\u6784\u5EFA-\u9A8C\u8BC1-\u4FEE\u590D&quot;\u95ED\u73AF\uFF0C\u4F8B\u5982\u4EE3\u7801\u751F\u6210\u540E\u81EA\u52A8\u8FD0\u884C\u6D4B\u8BD5\uFF0C\u5931\u8D25\u5219\u8981\u6C42 Agent \u81EA\u884C\u4FEE\u590D\u3002</li><li>\u53CD\u71B5 Agent\uFF1A\u5B9A\u671F\u626B\u63CF\u7CFB\u7EDF\uFF0C\u81EA\u52A8\u6E05\u7406\u8FC7\u65F6\u6587\u6863\u3001\u65E0\u6548\u4F9D\u8D56\u548C\u504F\u79BB\u67B6\u6784\u3002</li></ul></li></ul><hr><h2 id="\u{1F9E9}-\u6A21\u5757\u4E94-\u7F16\u6392\u4E0E\u534F\u8C03-orchestration-coordination" tabindex="-1">\u{1F9E9} \u6A21\u5757\u4E94\uFF1A\u7F16\u6392\u4E0E\u534F\u8C03 (Orchestration &amp; Coordination) <a class="header-anchor" href="#\u{1F9E9}-\u6A21\u5757\u4E94-\u7F16\u6392\u4E0E\u534F\u8C03-orchestration-coordination" aria-hidden="true">#</a></h2><p><strong>&quot;\u5927\u8111&quot;</strong>\uFF0C\u8D1F\u8D23\u5C06\u590D\u6742\u4EFB\u52A1\u62C6\u89E3\u5E76\u6709\u5E8F\u6267\u884C\u3002</p><ul><li><strong>\u5B9A\u4E49\u4E0E\u76EE\u7684</strong>\uFF1A\u5BF9\u591A\u6B65\u64CD\u4F5C\u6216\u591A\u89D2\u8272\u534F\u4F5C\u7684\u590D\u6742\u4EFB\u52A1\uFF0C\u901A\u8FC7\u7F16\u6392\u903B\u8F91\u62C6\u89E3\u4E3A&quot;\u8C03\u7814-\u89C4\u5212-\u6267\u884C-\u9A8C\u8BC1&quot;\u7B49\u72EC\u7ACB\u9636\u6BB5\uFF0C\u7BA1\u7406 Agent \u4E0E\u4EBA\u7C7B\u7684\u534F\u4F5C\u3002</li><li><strong>\u5B9E\u73B0\u65B9\u5F0F</strong>\uFF1A <ul><li>\u4EFB\u52A1\u62C6\u5206\u4E0E\u8C03\u5EA6\uFF1A\u901A\u8FC7\u7F16\u6392\u903B\u8F91\u5C06\u590D\u6742\u4EFB\u52A1\u62C6\u89E3\u4E3A\u53EF\u6267\u884C\u7684\u5B50\u4EFB\u52A1\uFF0C\u5206\u914D\u7ED9\u4E0D\u540C Agent \u5904\u7406\u3002</li><li>\u72B6\u6001\u7BA1\u7406\uFF1A\u7EF4\u62A4\u4EFB\u52A1\u6267\u884C\u7684\u5168\u5C40\u72B6\u6001\u548C\u8FDB\u5EA6\uFF0C\u786E\u4FDD\u4FE1\u606F\u4E0D\u4E22\u5931\u3002</li><li>\u6A21\u578B\u8DEF\u7531\uFF1A\u6839\u636E\u4EFB\u52A1\u7C7B\u578B\u548C\u96BE\u5EA6\uFF0C\u52A8\u6001\u9009\u62E9\u6700\u5408\u9002\u7684\u6A21\u578B\u6216\u5B50 Agent\u3002</li></ul></li></ul><hr><h2 id="\u{1F4C8}-\u6A21\u5757\u516D-\u71B5\u7BA1\u7406\u4E0E\u6301\u7EED\u6539\u8FDB-entropy-management" tabindex="-1">\u{1F4C8} \u6A21\u5757\u516D\uFF1A\u71B5\u7BA1\u7406\u4E0E\u6301\u7EED\u6539\u8FDB (Entropy Management) <a class="header-anchor" href="#\u{1F4C8}-\u6A21\u5757\u516D-\u71B5\u7BA1\u7406\u4E0E\u6301\u7EED\u6539\u8FDB-entropy-management" aria-hidden="true">#</a></h2><p><strong>&quot;\u514D\u75AB\u7CFB\u7EDF&quot;</strong>\uFF0C\u786E\u4FDD\u7CFB\u7EDF\u957F\u671F\u5065\u5EB7\u548C\u6301\u7EED\u8FDB\u5316\u3002</p><ul><li><strong>\u5B9A\u4E49\u4E0E\u76EE\u7684</strong>\uFF1A\u9632\u6B62\u7CFB\u7EDF\u968F\u65F6\u95F4\u63A8\u79FB\u800C&quot;\u8150\u5316&quot;\uFF08\u6587\u6863\u8FC7\u65F6\u3001\u67B6\u6784\u504F\u79BB\uFF09\uFF0C\u5EFA\u7ACB\u4ECE\u9519\u8BEF\u4E2D\u5B66\u4E60\u7684\u673A\u5236\u3002</li><li><strong>\u5B9E\u73B0\u65B9\u5F0F</strong>\uFF1A <ul><li>\u5B9E\u65F6\u6F14\u8FDB\u4E0E\u77E5\u8BC6\u6C89\u6DC0\uFF1A\u6BCF\u6B21 Agent \u72AF\u9519\u90FD\u662F\u6539\u8FDB\u7CFB\u7EDF\u7684\u4FE1\u53F7\uFF0C\u5206\u6790\u5931\u8D25\u6848\u4F8B\uFF0C\u8865\u5145\u7EA6\u675F\u89C4\u5219\u3001\u4F18\u5316\u4E0A\u4E0B\u6587\u3001\u5B8C\u5584\u5DE5\u5177\u3002</li><li>\u6C38\u4E45\u5316\u9519\u8BEF\u8BB0\u5F55\uFF1A\u5C06\u9519\u8BEF\u548C\u4FEE\u6B63\u65B9\u6848\u5199\u5165 <a href="http://CLAUDE.md" target="_blank" rel="noreferrer">CLAUDE.md</a> \u7B49\u957F\u671F\u8BB0\u5FC6\uFF0C\u786E\u4FDD\u6C38\u4E0D\u518D\u72AF\u3002</li></ul></li></ul><hr><p>\u{1F48E} <strong>\u603B\u7ED3</strong></p><p>\u8FD9\u516D\u4E2A\u6A21\u5757\u5E76\u975E\u5B64\u7ACB\u5B58\u5728\uFF0C\u5B83\u4EEC\u5171\u540C\u6784\u6210\u4E00\u4E2A\u76F8\u8F85\u76F8\u6210\u3001\u5FAA\u73AF\u53CD\u9988\u7684\u6709\u673A\u6574\u4F53\uFF1A</p><ol><li><strong>\u7EA6\u675F\u673A\u5236</strong> \u5212\u5B9A\u4E86\u5B89\u5168\u8FB9\u754C</li><li><strong>\u4E0A\u4E0B\u6587\u5DE5\u7A0B</strong> \u63D0\u4F9B\u4E86\u77E5\u8BC6\u548C\u4FE1\u606F</li><li><strong>\u5DE5\u5177\u96C6\u6210</strong> \u8D4B\u4E88 AI \u884C\u52A8\u80FD\u529B</li><li><strong>\u7F16\u6392\u4E0E\u534F\u8C03</strong> \u89C4\u5212\u4E86\u884C\u52A8\u8DEF\u5F84</li><li><strong>\u53CD\u9988\u56DE\u8DEF</strong> \u786E\u4FDD\u884C\u52A8\u7684\u6709\u6548\u6027</li><li><strong>\u71B5\u7BA1\u7406</strong> \u5B88\u62A4\u7CFB\u7EDF\u7684\u957F\u671F\u5065\u5EB7</li></ol><p>\u5B8C\u6574\u7684 Harness \u5DE5\u7A0B\u9700\u8981\u5C06\u8FD9\u516D\u4E2A\u6A21\u5757\u6709\u673A\u6574\u5408\uFF0C\u8BA9 AI Agent \u65E2\u667A\u80FD\u53C8\u53EF\u9760\u3002</p><hr><h2 id="\u76F8\u5173\u6587\u7AE0" tabindex="-1">\u76F8\u5173\u6587\u7AE0 <a class="header-anchor" href="#\u76F8\u5173\u6587\u7AE0" aria-hidden="true">#</a></h2><ul><li><a href="/thinkwithAI/harness/claw-code-omx-100k-stars.html">Claw Code\uFF1A\u5982\u4F55\u572824\u5C0F\u65F6\u5185\u83B7\u5F9710\u4E07Star</a> - \u4E86\u89E3 OMX \u591A Agent \u7F16\u6392\u5982\u4F55\u5728 24 \u5C0F\u65F6\u5185\u8FBE\u6210 100k Stars \u7684\u5B9E\u6218\u6848\u4F8B <em>\u672C\u7CFB\u5217\u540E\u7EED\u6587\u7AE0\u5C06\u6DF1\u5165\u5256\u6790\u5404\u6A21\u5757\u7684\u5B9E\u73B0\u7EC6\u8282\u548C\u6700\u4F73\u5B9E\u8DF5\u3002</em></li></ul>',36),l=[o];function a(s,g,h,d,u,c){return n(),e("div",null,l)}const q=t(i,[["render",a]]);export{m as __pageData,q as default};
